const candidates = [
  { name: "Alice Johnson", skills: "Python, NLP, Scikit-learn", experience: "3 years" },
  { name: "Bob Smith", skills: "Java, Spring Boot", experience: "5 years" },
  { name: "Carol White", skills: "Python, TensorFlow, Deep Learning", experience: "2 years" }
];

const results = candidates.map(c => ({
  name: c.name,
  score: 8,
  skills_match: c.skills.split(", "),
  recommendation: "shortlist",
  reason: "Skills match the requirements."
}));

return results.map(r => ({ json: r }));
